VALUES
  ('pukao-64311456-moex-00048', 'pukao-64311456', 'pukao-64311456-moex-114-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '依據我國老人福利法之規定，下列敘述何者錯誤？', '["所稱老人，指年滿六十五歲以上之人", "主管機關應至少每五年舉辦老人生活狀況調查，出版統計報告", "立法目的為維護老人尊嚴與健康，延緩老人失能，安定老人生活，保障老人權益，增進老人福利", "各級政府老人福利之經費來源為按年編列之老人福利預算，惟不包含私人或團體捐贈"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "9bac9cd4d224", "answer_pdf_sha1": "a8daa8efff43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "405", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00049', 'pukao-64311456', 'pukao-64311456-moex-114-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '依據我國性騷擾防治法之規定，下列敘述何者正確？', '["所稱權勢性騷擾，指對於因教育、訓練、醫療、公務、業務、求職或其他相類關係受自己監督、 照護、指導之人，利用權勢或機會為性騷擾", "組織之成員、受僱人或受服務人員人數達三十人以上者，方應設立申訴管道協調處理", "組織之成員、受僱人或受服務人員人數達五十人以上者，方應訂定性騷擾防治措施，且公開揭示之", "屬權勢性騷擾事件者，若性騷擾事件發生時被害人為成年者，應於知悉事件發生後一年內提出 申訴。但自性騷擾事件發生之日起逾三年者，不得提出"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "9bac9cd4d224", "answer_pdf_sha1": "a8daa8efff43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "405", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00050', 'pukao-64311456', 'pukao-64311456-moex-114-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '依據家庭暴力防治法對於民事保護令之規定，下列敘述何者錯誤？', '["保護令之聲請，由被害人住居所地之地方法院為唯一管轄之法院", "檢察官、警察機關或直轄市、縣（市）主管機關得向法院聲請保護令", "民事保護令分為通常保護令、暫時保護令及緊急保護令", "通常保護令之有效期間為二年以下"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "9bac9cd4d224", "answer_pdf_sha1": "a8daa8efff43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "405", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00051', 'pukao-64311456', 'pukao-64311456-moex-114-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '依據我國少年事件處理法之規定，下列敘述何者錯誤？', '["少年之保護管束，由少年保護官掌理之", "保護管束與感化教育之執行，其期間均不得逾三年", "少年轉介輔導處分及保護處分之執行，至多執行至滿十八歲為止", "保護管束之執行，已逾六月，著有成效，認無繼續之必要者，得檢具事證，聲請少年法院免除 其執行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "9bac9cd4d224", "answer_pdf_sha1": "a8daa8efff43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "405", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00052', 'pukao-64311456', 'pukao-64311456-moex-114-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '長期照顧服務之宗旨在於健全長期照顧服務體系提供長期照顧服務，下列敘述何者錯誤？', '["長期照顧管理中心指由地方主管機關指定以提供長照需要之評估及連結服務為目的之機關", "長期照顧服務方式中，小規模多機能服務屬於社區式服務", "家庭照顧者指於家庭中對失能者提供規律性照顧之主要親屬或家人", "長期照顧指身心失能持續已達或預期達六個月以上者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "9bac9cd4d224", "answer_pdf_sha1": "a8daa8efff43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "405", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00053', 'pukao-64311456', 'pukao-64311456-moex-114-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '依據精神衛生法之規定，精神醫療機構因病人病情急迫，經一位專科醫師認有必要，並依規定取 得同意後，得施行電痙攣治療。下列有關取得書面同意之敘述，何者錯誤？', '["病人為未滿七歲之未成年人，應經其法定代理人同意", "病人為成年人，但受監護宣告或輔助宣告者，應以其理解方式提供資訊，並應取得其監護人或 輔助人同意", "病人未滿十八歲以下之未成年人，應經其本人及其法定代理人同意", "監護人或輔助人依規定同意時，應尊重受監護宣告或輔助宣告者之意願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "9bac9cd4d224", "answer_pdf_sha1": "a8daa8efff43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "405", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00054', 'pukao-64311456', 'pukao-64311456-moex-114-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '依據性別平等工作法之規定，下列敘述何者正確？', '["性別、性傾向歧視之禁止、性騷擾之防治及促進工作平等措施，得視地方政府條件納入勞動檢 查項目", "地方主管機關設有就業歧視委員會者，性別平等工作會應與該委員會合併設置", "各級主管機關應設性別平等工作會，應置委員五人至十一人，任期一年", "產檢假、陪產檢及陪產假期間，薪資照給"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "9bac9cd4d224", "answer_pdf_sha1": "a8daa8efff43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "405", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00055', 'pukao-64311456', 'pukao-64311456-moex-114-d1a761c9', 'sub-pukao-64311456-03', NULL, 'single_choice', '下列國際法作為行政法法源之敘述，何者錯誤？', '["條約涉及人民之權利義務且具有法律上效力者，應送立法院審議", "條約與立法院制定之法律相牴觸時，應優先適用國內法律", "國際法須於條約或協定明定其內容，始可引用作為行政法法源", "經憲法法庭直接引用之國際公約，可以於授益行政的範圍內引用之"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "405", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00056', 'pukao-64311456', 'pukao-64311456-moex-114-d1a761c9', 'sub-pukao-64311456-03', NULL, 'single_choice', '行政程序法第5條規定：「行政行為之內容應明確」，下列敘述何者正確？', '["懲處之構成要件，法律不得以抽象概念表示", "所謂內容應該明確，僅限於行政處分", "書面行政處分書雖漏未記載處分相對人之性別，但已有足資辨別之特徵者，符合明確性原則", "行政指導無需符合明確性原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "405", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00057', 'pukao-64311456', 'pukao-64311456-moex-114-d1a761c9', 'sub-pukao-64311456-03', NULL, 'single_choice', '行政機關核發甲之商場開發許可時，因甲不能提供足夠之停車位，而要求其提供金錢改善社區之照明設施， 此要求違反下列何原則？', '["比例原則", "不當聯結禁止原則", "誠信原則", "平等原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "405", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL)
